import React, { useState } from 'react';


export default function GameBord(props) {
    const [playerDec, setPlayerDec] = useState([])
    const [computerDec, setComputerDec] = useState([])
    const [readyToStart, setReadyToStart] = useState(false)
    const [start, setStart] = useState(false)
    const [roundNumber, setRoundNumber] = useState(0)
    const [gameWon, setGameWon] = useState(false)
    const [pScore, setPScore] = useState(0)
    const [cScore, setCScore] = useState(0)
    const [pImg, setPImg] = useState("")
    const [cImg, setCImg] = useState("")
    const totalCards = 52
    const copyFromEatchCard = 4
    
    let createDec = () => {
        let mainDec = []
        for (let i = 1; i <= totalCards / copyFromEatchCard; i++) {
            for (let x = 0; x < copyFromEatchCard; x++) {
                mainDec.push(i)
            }
        }
        let pDec = []
        let cDec = []
        let rnd = 0
        while (mainDec.length > 0) {
            rnd = getRandomNum(mainDec.length)
            pDec.push(mainDec[rnd])
            mainDec.splice(rnd, 1)
            rnd = getRandomNum(mainDec.length)
            cDec.push(mainDec[rnd])
            mainDec.splice(rnd, 1)

        }
        console.log();
        setPlayerDec(pDec)
        setComputerDec(cDec)
        setReadyToStart(true)
    }

    let getRandomNum = (max) => {
        return Math.floor(Math.random() * max)
    }

    let startTheGame = () => {
        if (computerDec[roundNumber] > playerDec[roundNumber])
        setCScore(cScore + 1)
    else if (computerDec[roundNumber] < playerDec[roundNumber])
        setPScore(pScore + 1)
        console.log(playerDec)
        console.log(computerDec)
         setImg()
        setStart(true)
    }


    let nextCard = () => {
        setRoundNumber(roundNumber + 1)
        console.log(roundNumber)
 
        if (computerDec[roundNumber] > playerDec[roundNumber]) {
            setCScore(cScore + 1)
        } else if (computerDec[roundNumber] < playerDec[roundNumber]){
            setPScore(pScore + 1)
        }
        setImg()
    }


    let setImg =async () => {
        let a = "./cards/" + computerDec[roundNumber] + "-" + getR() + ".png"
        setCImg(a)
        let b = "./cards/" + playerDec[roundNumber] + "-" + getR() + ".png"
        setPImg(b)
    }



    let buttons = () => {
        console.log(roundNumber)
        if (roundNumber == ((totalCards / 2)))
            return <button onClick={() => finish()} >Finish</button>
        else
            return <button onClick={() => nextCard()} >Next draw!</button>
    }



    let finish = () => {
        if (computerDec[roundNumber] > playerDec[roundNumber]){
            setCScore(cScore + 1)}
        else if (computerDec[roundNumber] < playerDec[roundNumber]){
            setPScore(pScore + 1)}
        if (pScore < cScore){
            setGameWon(true)
            sendInfo(true)}
        else{
            setGameWon(false)
            sendInfo(false)}
    }



    let changeUser = () => {
        props.currentPage(props.pages.home)
        setPlayerDec([])
        setComputerDec([])
        setReadyToStart(false)
        setStart(false)
        setRoundNumber(0)
        setPScore(0)
        setCScore(0)

    }
    let rematch = () => {
        props.currentPage(props.pages.game)
        setPlayerDec([])
        setComputerDec([])
        setReadyToStart(false)
        setStart(false)
        setRoundNumber(0)
        setPScore(0)
        setCScore(0)

    }

    let scores = () => {
        if (gameWon)
            return <h1>you won this time!</h1>
        else
            return <h1>you lost!</h1>
    }



    let getR = () => {
        return Math.floor(Math.random() * (4 - 1) + 1);
    }


    let sendImg = (img) => {
        return <img src={img} />
    }



    let sendInfo =  (didWon) => {
        props.saveInfo(props.playerName, didWon)
    }



    if (!readyToStart) {
        return (
            <div>
                <h1>create a new game</h1>
                <button onClick={() => createDec()} >Create a new game!</button>
            </div>
        )
    }
    else if (!start) {
        return (
            <div>
                <h3>Ready to play???</h3>
                <button onClick={() => startTheGame()}>Draw</button>

            </div>
        )
    }
    else if ((totalCards / 2) > roundNumber ) {
        return (
            <div>
                <h2> round number: {(roundNumber+1) + "/" + ((totalCards / 2))}</h2>
                <h3>{props.playerName + "'s score: " + pScore + "-VS-" + "Computer's score: " + cScore}</h3>
                <h4>Computer:</h4>
                {sendImg(cImg)}
                <h4>{props.playerName}:</h4>
                {sendImg(pImg)}<br></br>
                {buttons()}
            </div>
        )
    }
    else
        return (
            <div>
                {scores()}
                <button onClick={rematch}>play Again as {props.playerName}</button>
                <button onClick={changeUser}>play as different name</button>
                {props.theList()}
            </div>
        )
}
